class Solution {
    public int possibleStringCount(String word, int k) {
        long[] groups = new long[word.length() + 1];
        groups[0] = 1;
        int count = 1;
        for (char c : word.toCharArray()) {
            if (count > 1 && c == word[word.length() - count]) {
                count--;
            } else {
                count = 1;
            }
            groups[count] = (groups[count] + 1) % (int) 1e9 + 7;
        }
        long res = 0;
        for (int i = k; i <= word.length(); i++) {
            res = (res + groups[i]) % (int) 1e9 + 7;
        }
        return (int) res;
    }
}
